import * as React from "react";
import { cn } from "../../lib/utils";
import "./Skeleton.css";

/**
 * EXPERIMENTAL — not ready for productive usage, API subject to change.
 */
export interface SkeletonProps extends React.ComponentProps<"div"> {
  /** animation style: "shimmer" (Figma sweep) or "pulse" (opacity fade) */
  animation?: "shimmer" | "pulse";
}

/**
 * EXPERIMENTAL — not ready for productive usage, API subject to change.
 *
 * Skeleton placeholder component for loading states.
 * Compose by setting height, width, and border-radius via className.
 */
export function Skeleton({
  className,
  animation = "shimmer",
  ...props
}: SkeletonProps) {
  return (
    <div
      data-slot="skeleton"
      className={cn(
        "rounded-md bg-[#e1e1e1]/50 dark:bg-white/10",
        animation === "shimmer" && "skeleton-shimmer",
        animation === "pulse" && "animate-pulse",
        className,
      )}
      {...props}
    />
  );
}

Skeleton.displayName = "Skeleton";
